import io.gatling.javaapi.http.HttpDsl.*;
import java.time.Duration;

public class PaymentLoadSimulation extends Simulation {

    HttpProtocolBuilder httpProtocol = http
        .baseUrl("http://localhost:8080")
        .acceptHeader("application/json")
        .contentTypeHeader("application/json")
        .header("X-API-Key", "rzp_test_perf_key");

    ScenarioBuilder scenario = scenario("Razorpay Payment Load")
        .exec(
            http("POST create payment")
                .post("/api/payments")
                .body(StringBody("{\"amount\": 5000, \"gateway\": \"HDFC\"}"))
                .check(status().is(200))
                .check(responseTimeInMillis().lte(1000))
        )
        .pause(Duration.ofMillis(100)); // 100ms think time between requests

    // Load injection + assertions:
    {
        setUp(
            scenario.injectOpen(
                atOnceUsers(10)  // spike: 10 users simultaneously
            ).protocols(httpProtocol)
        ).assertions(
            global().responseTime().percentile3().lt(1000), // p99 < 1000ms
            global().successfulRequests().percent().gt(95.0) // >95% success
        );
    }
}

