// k6 load test: zerodha-portfolio-load.js
import http from 'k6/http';
import { check, sleep } from 'k6';
import { Rate } from 'k6/metrics';

// Custom metric: track error rate:
const errorRate = new Rate('errors');

// Test configuration:
export const options = {
  vus: 100,          // 100 virtual users
  duration: '30s',   // run for 30 seconds

  // Thresholds: build fails if breached:
  thresholds: {
    http_req_duration: ['p(99)<500'],    // p99 < 500ms
    errors: ['rate<0.01'],              // error rate < 1%
    http_req_failed: ['rate<0.01'],     // HTTP failures < 1%
  },
};

// Test function (runs once per VU per iteration):
export default function () {
  const userId = `MRC-${Math.floor(Math.random() * 1000)}`;

  const res = http.get(`http://localhost:8080/api/portfolio/${userId}`, {
    headers: {
      'Authorization': 'Bearer test-token-perf',
      'Accept': 'application/json',
    },
  });

  // Assertions (logged, not test-failing):
  const ok = check(res, {
    'status is 200': (r) => r.status === 200,
    'response time < 500ms': (r) => r.timings.duration < 500,
    'has merchantId field': (r) => JSON.parse(r.body).merchantId !== undefined,
  });

  errorRate.add(!ok);
  sleep(0.1); // 100ms think time
}

// Run: k6 run zerodha-portfolio-load.js

// K6 vs GATLING:
// k6:
//   - JavaScript (familiar to frontend devs)
//   - Easy CI integration (k6 run → exit code 1 if thresholds fail)
//   - Great for API load tests, REST/GraphQL
//   - Cloud execution: k6 Cloud
// Gatling:
//   - Scala/Java DSL (Java devs prefer)
//   - Rich HTML reports out of the box
//   - Better for complex scenarios (shopping cart flows)
//   - Akka-based: very high concurrency per machine

