import io.gatling.javaapi.core.*;
import io.gatling.javaapi.core.CoreDsl.*;
import io.gatling.javaapi.http.*;
import io.gatling.javaapi.http.HttpDsl.*;
import java.time.Duration;

public class PaymentStressSimulation extends Simulation {

    HttpProtocolBuilder http = http
        .baseUrl("http://localhost:8080")
        .acceptHeader("application/json");

    ScenarioBuilder scn = scenario("Payment Stress Test")
        .exec(
            http("POST payment")
                .post("/api/payments")
                .header("Content-Type", "application/json")
                .body(StringBody("{\"amount\": 5000, \"gateway\": \"HDFC\"}"))
                .check(status().in(200, 503)) // accept both — stress test expects some 503s
        ).pause(Duration.ofMillis(50));

    {
        setUp(
            scn.injectOpen(
                // Staircase stress pattern:
                rampUsersPerSec(0).to(100).during(Duration.ofSeconds(30)),   // warm up
                constantUsersPerSec(100).during(Duration.ofSeconds(60)),      // 100/s for 60s
                rampUsersPerSec(100).to(500).during(Duration.ofSeconds(30)),  // ramp to 500
                constantUsersPerSec(500).during(Duration.ofSeconds(60)),      // 500/s for 60s
                rampUsersPerSec(500).to(1000).during(Duration.ofSeconds(30)), // ramp to 1000
                constantUsersPerSec(1000).during(Duration.ofSeconds(60))      // 1000/s for 60s
            ).protocols(http)
        ).assertions(
            // At peak: we accept higher failure rate (stress test)
            global().responseTime().percentile3().lt(2000),   // p99 < 2s (lenient — stress)
            global().successfulRequests().percent().gt(80.0), // 80% success at stress level
            // Key assertion: system DOES NOT crash (returns 200 or 503, never hangs forever)
            global().requestsPerSec().gte(100)  // still processing requests
        );
    }
}

public class StressDoc { public static void main(String[] a) {
    System.out.println("Stress test: staircase ramp, find breaking point, graceful degradation");
} }

