// MRC-004,500,VISA

public class PaymentFeederSimulation extends Simulation {

    // CSV Feeder: each virtual user gets a different row:
    FeederBuilder<String> feeder = csv("payments.csv").circular(); // repeat when exhausted

    HttpProtocolBuilder http = http
        .baseUrl("http://localhost:8080")
        .acceptHeader("application/json");

    ScenarioBuilder scn = scenario("Payment with realistic data")
        .feed(feeder)  // Inject feeder values into session
        .exec(
            http("POST payment with #{merchantId}")
                .post("/api/payments")
                .header("Content-Type", "application/json")
                .header("X-Merchant-Id", "#{merchantId}")       // from feeder
                .body(StringBody(
                    "{\"amount\": #{amount}, \"gateway\": \"#{gateway}\"}"
                ))                                                // from feeder
                .check(status().is(200))
        ).pause(Duration.ofMillis(100));

    {
        setUp(
            scn.injectOpen(atOnceUsers(5)).protocols(http)
        ).assertions(
            global().successfulRequests().percent().gt(95.0)
        );
    }
}

// WHY FEEDERS:
