// Performance regression checker:
@Service
class PerformanceRegressionChecker {
    record PerformanceBaseline(long p99Ms, double errorRate) {}
    record PerformanceResult(long p99Ms, double errorRate) {}

    static final double MAX_REGRESSION_PERCENT = 0.10; // 10% regression allowed
    static final double MAX_ERROR_RATE = 0.01;         // 1% error rate maximum

    boolean isRegressionAcceptable(PerformanceBaseline baseline, PerformanceResult current) {
        long maxAllowedP99 = (long)(baseline.p99Ms() * (1 + MAX_REGRESSION_PERCENT));
        return current.p99Ms() <= maxAllowedP99
            && current.errorRate() <= MAX_ERROR_RATE;
    }

    String regressionReport(PerformanceBaseline baseline, PerformanceResult current) {
        long maxAllowed = (long)(baseline.p99Ms() * 1.10);
        boolean p99ok = current.p99Ms() <= maxAllowed;
        boolean errOk = current.errorRate() <= MAX_ERROR_RATE;
        return String.format(
            "p99: %dms (baseline %dms, max %dms) → %s | errors: %.1f%% (max 1%%) → %s",
            current.p99Ms(), baseline.p99Ms(), maxAllowed,
            p99ok ? "PASS" : "FAIL",
            current.errorRate() * 100,
            errOk ? "PASS" : "FAIL"
        );
    }
}

