@SpringBootTest
class PerformanceRegressionTest {
    @Autowired PerformanceRegressionChecker checker;

    @Test void noRegression_passes() {
        var baseline = new PerformanceRegressionChecker.PerformanceBaseline(320L, 0.002);
        var current = new PerformanceRegressionChecker.PerformanceResult(340L, 0.003);
        assertTrue(checker.isRegressionAcceptable(baseline, current));
        // 340 <= 320 * 1.10 = 352 → PASS
    }
    @Test void largeRegression_fails() {
        var baseline = new PerformanceRegressionChecker.PerformanceBaseline(320L, 0.002);
        var current = new PerformanceRegressionChecker.PerformanceResult(400L, 0.003);
        assertFalse(checker.isRegressionAcceptable(baseline, current));
        // 400 > 320 * 1.10 = 352 → FAIL
    }
}

