import io.gatling.javaapi.core.*;
import io.gatling.javaapi.core.CoreDsl.*;
import io.gatling.javaapi.http.*;
import io.gatling.javaapi.http.HttpDsl.*;
import java.time.Duration;

public class RazorpayMixedLoadSimulation extends Simulation {

    HttpProtocolBuilder http = http
        .baseUrl("http://localhost:8080")
        .acceptHeader("application/json")
        .header("X-API-Key", "rzp_test_load_key");

    // Scenario 1: Payment creation (70% of traffic)
    ScenarioBuilder paymentScenario = scenario("Create Payment")
        .exec(
            http("POST /api/payments")
                .post("/api/payments")
                .header("Content-Type", "application/json")
                .body(StringBody("{\"amount\": #{amount}, \"gateway\": \"HDFC\"}"
                    .replace("#{amount}", String.valueOf((long)(Math.random() * 100_000) + 1))))
                .check(status().is(200))
                .check(jsonPath("$.paymentId").saveAs("paymentId")) // save for refund
        ).pause(Duration.ofMillis(200));

    // Scenario 2: Refund query (30% of traffic)
    ScenarioBuilder refundScenario = scenario("Query Refund")
        .exec(
            http("GET /api/refunds")
                .get("/api/refunds/PAY-" + System.nanoTime())
                .check(status().in(200, 404)) // 404 OK — payment may not exist
        ).pause(Duration.ofMillis(100));

    {
        setUp(
            // 70% payments, 30% refunds:
            paymentScenario.injectOpen(rampUsers(70).during(Duration.ofSeconds(60))),
            refundScenario.injectOpen(rampUsers(30).during(Duration.ofSeconds(60)))
        ).protocols(http)
         .assertions(
            global().responseTime().percentile3().lt(500),
            global().successfulRequests().percent().gt(99.0)
        );
    }
}

