import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

@Service
class MemoryLeakDetector {
    private final List<Long> heapSnapshotsMb = new ArrayList<>();
    private static final long MAX_GROWTH_MB_PER_INTERVAL = 50;

    public void takeSnapshot() {
        Runtime rt = Runtime.getRuntime();
        long usedMb = (rt.totalMemory() - rt.freeMemory()) / 1_048_576;
        heapSnapshotsMb.add(usedMb);
    }

    // Detects consistent heap growth (not just GC noise):
    public boolean isPotentialLeak() {
        if (heapSnapshotsMb.size() < 3) return false;
        int n = heapSnapshotsMb.size();
        long growthPerInterval = heapSnapshotsMb.get(n-1) - heapSnapshotsMb.get(n-3);
        return growthPerInterval > MAX_GROWTH_MB_PER_INTERVAL * 2; // 100MB over 3 snapshots
    }

    // Returns trend: positive = growing, negative = shrinking
    public long heapTrendMbPerInterval() {
        if (heapSnapshotsMb.size() < 2) return 0;
        int n = heapSnapshotsMb.size();
        return heapSnapshotsMb.get(n-1) - heapSnapshotsMb.get(0);
    }

    public void injectGrowthForTest(long... snapshotsMb) {
        heapSnapshotsMb.clear();
        for (long s : snapshotsMb) heapSnapshotsMb.add(s);
    }
}

@SpringBootTest
class MemoryLeakTest {
    @Autowired MemoryLeakDetector detector;

    @Test void growingHeap_detectedAsLeak() {
        detector.injectGrowthForTest(200, 280, 370, 450); // 250MB growth over 3 intervals
        assertTrue(detector.isPotentialLeak());
        assertTrue(detector.heapTrendMbPerInterval() > 0);
    }
    @Test void stableHeap_notALeak() {
        detector.injectGrowthForTest(200, 210, 195, 205); // GC noise, not leak
        assertFalse(detector.isPotentialLeak()); // 5MB variation = not a leak
    }
}

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

@Service
class RzpPerfChecker {
    record Baseline(long p99, double errRate) {}
    record Result(long p99, double errRate, long heapGrowthMb) {}

    boolean acceptable(Baseline b, Result r) {
        long maxP99 = (long)(b.p99() * 1.10); // 10% regression allowed
        return r.p99() <= maxP99
            && r.errRate() <= b.errRate() * 2.0  // error rate can double
            && r.heapGrowthMb() < 200;           // heap growth < 200MB
    }

    String report(Baseline b, Result r) {
        boolean ok = acceptable(b, r);
        return String.format(
            "p99=%dms(baseline=%dms,max=%dms) errRate=%.2f%% heapGrowth=%dMB → %s",
            r.p99(), b.p99(), (long)(b.p99()*1.1),
            r.errRate()*100, r.heapGrowthMb(),
            ok ? "PASS" : "FAIL");
    }
}

@Service
class RzpSoakAnalyzer {
    List<Long> samples = new ArrayList<>();
    void addSample(long mb) { samples.add(mb); }
    boolean isLeaking() {
        if (samples.size() < 3) return false;
        int n = samples.size();
        return samples.get(n-1) - samples.get(0) > 150;
    }
    void reset() { samples.clear(); }
}

@SpringBootTest
class RzpPerfSuiteTest {
    @Autowired RzpPerfChecker checker;
    @Autowired RzpSoakAnalyzer soak;

    @Test void performance_noRegression() {
        var b = new RzpPerfChecker.Baseline(320L, 0.002);
        var r = new RzpPerfChecker.Result(340L, 0.003, 50L);
        assertTrue(checker.acceptable(b, r));
        assertTrue(checker.report(b, r).contains("PASS"));
    }
    @Test void performance_regressionDetected() {
        var b = new RzpPerfChecker.Baseline(320L, 0.002);
        var r = new RzpPerfChecker.Result(400L, 0.003, 50L); // 25% regression
        assertFalse(checker.acceptable(b, r));
        assertTrue(checker.report(b, r).contains("FAIL"));
    }
    @Test void soak_detectsMemoryLeak() {
        soak.reset();
        soak.addSample(200); soak.addSample(280); soak.addSample(370); // 170MB growth
        assertTrue(soak.isLeaking());
    }
}

import org.springframework.stereotype.*;
