@Service
class TradeDataGenerator {
    private final Random rng = new Random(42); // seeded for reproducibility
    private static final List<String[]> WEIGHTED_SYMBOLS = List.of(
        new String[]{ "RELIANCE", "RELIANCE", "RELIANCE", "RELIANCE", "RELIANCE" },  // 25%
        new String[]{ "TCS", "TCS", "TCS", "TCS" },                                   // 20%
        new String[]{ "INFY", "INFY", "INFY" },                                        // 15%
        new String[]{ "HDFCBANK", "ICICIBANK", "WIPRO", "AXISBANK", "BAJFINANCE",     // 40%
                      "TATAMOTORS", "LTIM", "SBIN" }
    );
    private final List<String> symbolPool = buildPool();

    private List<String> buildPool() {
        List<String> pool = new ArrayList<>();
        for (String[] group : WEIGHTED_SYMBOLS) pool.addAll(Arrays.asList(group));
        return pool;
    }

    public String randomSymbol() {
        return symbolPool.get(rng.nextInt(symbolPool.size()));
    }

    // Log-normal amount: most 1000-50000, some larger
    public long randomAmountPaise() {
        double logNormal = Math.exp(rng.nextGaussian() * 1.2 + 8.5); // mean ~₹5000
        long amountPaise = (long)(logNormal * 100); // convert to paise
        return Math.max(100_00L, Math.min(amountPaise, 1_00_00_000L)); // clamp 100-1_000_000
    }

    public Map<String, Object> generateTrade() {
        return Map.of(
            "symbol", randomSymbol(),
            "amountPaise", randomAmountPaise(),
            "orderType", rng.nextBoolean() ? "BUY" : "SELL",
            "merchantId", "MRC-" + (rng.nextInt(1000) + 1)
        );
    }
}

@SpringBootTest
class TradeDataGenTest {
    @Autowired TradeDataGenerator gen;

    @Test void distribution_RELIANCE_isHighest() {
        Map<String, Long> counts = new HashMap<>();
        for (int i = 0; i < 1000; i++) {
            String sym = gen.randomSymbol();
            counts.merge(sym, 1L, Long::sum);
        }
        assertTrue(counts.get("RELIANCE") > counts.get("TCS"),
            "RELIANCE should be more frequent than TCS");
        assertTrue(counts.get("RELIANCE") > 150, // ~25% of 1000
            "RELIANCE should be at least 15% of trades");
    }
    @Test void amounts_inValidRange() {
        for (int i = 0; i < 100; i++) {
            long amount = gen.randomAmountPaise();
            assertTrue(amount >= 100_00L, "min 100 paise = ₹1");
            assertTrue(amount <= 1_00_00_000L, "max 1 crore paise = ₹1L");
        }
    }
}

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

record PerfBaseline(long p99Ms, double errRate, long heapMb) {}
record PerfResult(long p99Ms, double errRate, long heapMb) {}

@Service
class PerformanceSuite {
    boolean isAcceptable(PerfBaseline b, PerfResult r) {
        return r.p99Ms() <= b.p99Ms() * 1.10
            && r.errRate() <= Math.max(b.errRate() * 2, 0.01)
            && r.heapMb() < b.heapMb() + 200;
    }
    String reportSummary(PerfBaseline b, PerfResult r) {
        boolean ok = isAcceptable(b, r);
        return (ok ? "PASS" : "FAIL") + " p99=" + r.p99Ms() + "ms err=" +
               String.format("%.2f%%", r.errRate()*100) + " heap=" + r.heapMb() + "MB";
    }
}

@Service
class RegressionHistory {
    private final Deque<Long> history = new ArrayDeque<>(5);
    void record(long p99) {
        if (history.size() >= 5) history.pollFirst();
        history.addLast(p99);
    }
    boolean isRegressionTrend() {
        if (history.size() < 3) return false;
        List<Long> list = new ArrayList<>(history);
        // Check if last 3 values are strictly increasing:
        int n = list.size();
        return list.get(n-1) > list.get(n-2) && list.get(n-2) > list.get(n-3);
    }
    double trendPercent() {
        if (history.size() < 2) return 0;
        List<Long> list = new ArrayList<>(history);
        return (double)(list.get(list.size()-1) - list.get(0)) / list.get(0) * 100;
    }
}

@SpringBootTest
class M25T4SynthesisTest {
    @Autowired PerformanceSuite suite;
    @Autowired RegressionHistory hist;

    @Test void acceptable_performance_passes() {
        var b = new PerfBaseline(300L, 0.005, 512L);
        var r = new PerfResult(320L, 0.006, 600L);
        assertTrue(suite.isAcceptable(b, r));
        assertTrue(suite.reportSummary(b, r).startsWith("PASS"));
    }
    @Test void regression_fails() {
        var b = new PerfBaseline(300L, 0.005, 512L);
        var r = new PerfResult(400L, 0.005, 512L); // 33% p99 regression
        assertFalse(suite.isAcceptable(b, r));
        assertTrue(suite.reportSummary(b, r).startsWith("FAIL"));
    }
    @Test void trend_detected() {
        hist.record(300); hist.record(320); hist.record(350);
        assertTrue(hist.isRegressionTrend()); // 300→320→350: trending up
    }
    @Test void stable_not_a_trend() {
        hist.record(300); hist.record(290); hist.record(310);
        assertFalse(hist.isRegressionTrend()); // 300→290→310: not monotonically increasing
    }
}
